/**
 * ProbabilityChart — Polymarket-style multi-line probability chart.
 *
 * Shows outcome probabilities over time for multi-outcome question markets.
 * Each outcome gets its own colored step-function line.
 * NOT for binary markets — use ProbabilityBar + LivePriceChart instead.
 *
 * Usage:
 *   const { series } = useProbabilityHistory(questionMarkets)
 *   <ProbabilityChart series={series} />
 */

"use client";

import { useEffect, useRef, useState, useCallback } from "react";

/** Auto-assigned color palette — 8 colors, wraps around for more series */
export const OUTCOME_COLORS = [
  "#ef4444", // red
  "#f59e0b", // amber
  "#3b82f6", // blue
  "#8b5cf6", // violet
  "#10b981", // emerald
  "#06b6d4", // cyan
  "#f43f5e", // rose
  "#84cc16", // lime
];

export interface OutcomeSeries {
  /** Unique ID (e.g. coin name) */
  id: string;
  /** Display label (e.g. "Akami", "Canned Tuna") */
  label: string;
  /** Line color — auto-assigned from OUTCOME_COLORS if not provided */
  color?: string;
  /** History: { time: unixSeconds, value: 0-1 }[] */
  data: Array<{ time: number; value: number }>;
  /** Current live value (0-1) */
  currentValue?: number;
}

export interface ProbabilityChartProps {
  series: OutcomeSeries[];
  /** Chart height in px. Default: 220 */
  height?: number;
  /** Theme: "light" | "dark". Default: "dark" */
  theme?: "light" | "dark";
  /** Additional CSS classes */
  className?: string;
}

// ---- helpers ----

function resolveColor(s: OutcomeSeries, idx: number): string {
  return s.color ?? OUTCOME_COLORS[idx % OUTCOME_COLORS.length];
}

function hexToRgb(hex: string): [number, number, number] {
  const r = parseInt(hex.slice(1, 3), 16);
  const g = parseInt(hex.slice(3, 5), 16);
  const b = parseInt(hex.slice(5, 7), 16);
  return [r, g, b];
}

function formatPercent(v: number): string {
  return `${(v * 100).toFixed(1)}%`;
}

function formatTimeLabel(unixSec: number, rangeSec: number): string {
  const d = new Date(unixSec * 1000);
  if (rangeSec > 3 * 24 * 3600) {
    return d.toLocaleDateString("en-US", { month: "short", day: "numeric" });
  }
  return d.toLocaleTimeString("en-US", {
    hour: "2-digit",
    minute: "2-digit",
    hour12: false,
  });
}

// ---- main component ----

/**
 * Multi-line step-function probability chart for question markets (3+ outcomes).
 *
 * Renders a canvas for performance with a div overlay for crisp legend + tooltip text.
 */
export function ProbabilityChart({
  series,
  height = 220,
  theme = "dark",
  className = "",
}: ProbabilityChartProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const isDark = theme === "dark";

  // ---- hover state ----
  const [hoverX, setHoverX] = useState<number | null>(null);
  const [hoverData, setHoverData] = useState<
    Array<{ label: string; value: number; color: string }> | null
  >(null);
  const [hoverTime, setHoverTime] = useState<number | null>(null);
  const [tooltipLeft, setTooltipLeft] = useState(0);

  // ---- draw ----

  useEffect(() => {
    const canvas = canvasRef.current;
    const container = containerRef.current;
    if (!canvas || !container) return;

    const width = container.clientWidth;
    if (width === 0) return;

    const dpr = window.devicePixelRatio || 1;
    canvas.width = width * dpr;
    canvas.height = height * dpr;
    canvas.style.width = `${width}px`;
    canvas.style.height = `${height}px`;

    const ctx = canvas.getContext("2d");
    if (!ctx) return;
    ctx.scale(dpr, dpr);

    ctx.clearRect(0, 0, width, height);

    if (series.length === 0) return;

    // Gather all data points to compute time range
    const allTimes = series.flatMap((s) => s.data.map((d) => d.time));
    if (allTimes.length === 0) return;

    const paddingTop = 8;
    const paddingBottom = 22;
    const paddingLeft = 4;
    const paddingRight = 52;

    const chartW = width - paddingLeft - paddingRight;
    const chartH = height - paddingTop - paddingBottom;

    const minT = Math.min(...allTimes);
    const maxT = Math.max(...allTimes);
    const tRange = maxT - minT || 1;

    // Y range: auto-scale with some padding
    const allValues = series.flatMap((s) => s.data.map((d) => d.value));
    const rawMin = Math.min(...allValues);
    const rawMax = Math.max(...allValues);
    const valuePad = (rawMax - rawMin) * 0.1 || 0.05;
    const yMin = Math.max(0, rawMin - valuePad);
    const yMax = Math.min(1, rawMax + valuePad);
    const yRange = yMax - yMin || 0.1;

    function toX(t: number) {
      return paddingLeft + ((t - minT) / tRange) * chartW;
    }
    function toY(v: number) {
      return paddingTop + chartH - ((v - yMin) / yRange) * chartH;
    }

    // ---- grid lines ----
    const gridColor = isDark ? "rgba(255,255,255,0.06)" : "rgba(0,0,0,0.07)";
    ctx.strokeStyle = gridColor;
    ctx.lineWidth = 0.5;
    ctx.setLineDash([]);

    const gridSteps = 4;
    const yStep = (yMax - yMin) / gridSteps;
    for (let i = 0; i <= gridSteps; i++) {
      const v = yMin + i * yStep;
      const y = toY(v);
      ctx.beginPath();
      ctx.moveTo(paddingLeft, y);
      ctx.lineTo(paddingLeft + chartW, y);
      ctx.stroke();

      // Y-axis label
      ctx.fillStyle = isDark ? "rgba(255,255,255,0.3)" : "rgba(0,0,0,0.3)";
      ctx.font = "10px ui-monospace, monospace";
      ctx.textAlign = "left";
      ctx.fillText(
        `${Math.round(v * 100)}%`,
        paddingLeft + chartW + 4,
        y + 3,
      );
    }

    // ---- step-function lines per series ----
    for (let si = 0; si < series.length; si++) {
      const s = series[si];
      if (s.data.length < 2) continue;

      const color = resolveColor(s, si);
      const [r, g, b] = hexToRgb(color);

      // Sort data by time
      const pts = [...s.data].sort((a, b) => a.time - b.time);

      ctx.strokeStyle = color;
      ctx.lineWidth = 1.8;
      ctx.lineJoin = "miter";
      ctx.lineCap = "square";
      ctx.setLineDash([]);

      ctx.beginPath();
      for (let i = 0; i < pts.length; i++) {
        const x = toX(pts[i].time);
        const y = toY(pts[i].value);
        if (i === 0) {
          ctx.moveTo(x, y);
        } else {
          // Step function: horizontal then vertical
          const prevY = toY(pts[i - 1].value);
          ctx.lineTo(x, prevY); // horizontal segment
          ctx.lineTo(x, y);     // vertical jump
        }
      }
      ctx.stroke();

      // Subtle fill under the step line
      const lastPt = pts[pts.length - 1];
      const firstPt = pts[0];
      ctx.lineTo(toX(lastPt.time), paddingTop + chartH);
      ctx.lineTo(toX(firstPt.time), paddingTop + chartH);
      ctx.closePath();
      ctx.fillStyle = `rgba(${r},${g},${b},0.06)`;
      ctx.fill();

      // Pulsing dot at current value (right edge)
      const liveValue = s.currentValue ?? lastPt.value;
      const dotX = toX(lastPt.time);
      const dotY = toY(liveValue);

      ctx.fillStyle = color;
      ctx.beginPath();
      ctx.arc(dotX, dotY, 3.5, 0, Math.PI * 2);
      ctx.fill();

      // Glow ring
      ctx.strokeStyle = color;
      ctx.lineWidth = 1;
      ctx.globalAlpha = 0.3;
      ctx.beginPath();
      ctx.arc(dotX, dotY, 6.5, 0, Math.PI * 2);
      ctx.stroke();
      ctx.globalAlpha = 1;
    }

    // ---- hover crosshair ----
    if (hoverX !== null) {
      const hx = Math.max(paddingLeft, Math.min(paddingLeft + chartW, hoverX));
      ctx.strokeStyle = isDark ? "rgba(255,255,255,0.2)" : "rgba(0,0,0,0.2)";
      ctx.lineWidth = 1;
      ctx.setLineDash([3, 3]);
      ctx.beginPath();
      ctx.moveTo(hx, paddingTop);
      ctx.lineTo(hx, paddingTop + chartH);
      ctx.stroke();
      ctx.setLineDash([]);
    }

    // ---- time axis labels ----
    ctx.fillStyle = isDark ? "rgba(255,255,255,0.25)" : "rgba(0,0,0,0.25)";
    ctx.font = "10px ui-monospace, monospace";
    ctx.textAlign = "center";

    const timePoints = [0, Math.floor(allTimes.length / 2), allTimes.length - 1];
    const sortedTimes = [...allTimes].sort((a, b) => a - b);
    for (const idx of timePoints) {
      const t = sortedTimes[Math.min(idx, sortedTimes.length - 1)];
      if (t === undefined) continue;
      ctx.fillText(
        formatTimeLabel(t, tRange),
        toX(t),
        paddingTop + chartH + 14,
      );
    }
  }, [series, height, isDark, hoverX]);

  // ---- mouse/touch interaction ----

  const handleMouseMove = useCallback(
    (e: React.MouseEvent<HTMLDivElement>) => {
      const container = containerRef.current;
      if (!container || series.length === 0) return;

      const rect = container.getBoundingClientRect();
      const mx = e.clientX - rect.left;

      // Compute paddings to match draw logic
      const paddingLeft = 4;
      const paddingRight = 52;
      const chartW = container.clientWidth - paddingLeft - paddingRight;

      const allTimes = series.flatMap((s) => s.data.map((d) => d.time));
      if (allTimes.length === 0) return;

      const minT = Math.min(...allTimes);
      const maxT = Math.max(...allTimes);
      const tRange = maxT - minT || 1;

      // Find timestamp at cursor
      const relX = mx - paddingLeft;
      const tAtCursor = minT + (relX / chartW) * tRange;

      // For each series, find the value at cursor using step-function logic:
      // value = the last data point whose time <= tAtCursor
      const hoverValues = series.map((s, i) => {
        const pts = [...s.data].sort((a, b) => a.time - b.time);
        let val = pts[0]?.value ?? 0;
        for (const p of pts) {
          if (p.time <= tAtCursor) val = p.value;
          else break;
        }
        return {
          label: s.label,
          value: val,
          color: resolveColor(s, i),
        };
      });

      // Nearest timestamp
      let nearestT = allTimes[0];
      let nearestDist = Infinity;
      for (const t of allTimes) {
        const d = Math.abs(t - tAtCursor);
        if (d < nearestDist) {
          nearestDist = d;
          nearestT = t;
        }
      }

      // Clamp tooltip position so it doesn't go off the right edge
      const tooltipEstWidth = 140;
      const clamped = Math.min(mx + 12, container.clientWidth - tooltipEstWidth - 4);

      setHoverX(mx);
      setHoverData(hoverValues);
      setHoverTime(nearestT);
      setTooltipLeft(clamped);
    },
    [series],
  );

  const handleMouseLeave = useCallback(() => {
    setHoverX(null);
    setHoverData(null);
    setHoverTime(null);
  }, []);

  const handleTouchMove = useCallback(
    (e: React.TouchEvent<HTMLDivElement>) => {
      e.preventDefault();
      const touch = e.touches[0];
      if (!touch) return;
      // Synthesize a mouse-like event object
      const synth = {
        clientX: touch.clientX,
        clientY: touch.clientY,
      } as React.MouseEvent<HTMLDivElement>;
      handleMouseMove(synth);
    },
    [handleMouseMove],
  );

  return (
    <div className={`relative ${className}`}>
      {/* Legend bar */}
      <div className="flex flex-wrap items-center gap-x-4 gap-y-1 mb-2 px-1">
        {series.map((s, i) => {
          const color = resolveColor(s, i);
          const pct = s.currentValue !== undefined
            ? formatPercent(s.currentValue)
            : s.data.length > 0
              ? formatPercent(s.data[s.data.length - 1].value)
              : null;
          return (
            <div key={s.id} className="flex items-center gap-1.5 min-w-0">
              <span
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: "50%",
                  background: color,
                  display: "inline-block",
                  flexShrink: 0,
                }}
              />
              <span className="text-[11px] text-muted-foreground truncate">
                {s.label}
              </span>
              {pct && (
                <span
                  className="text-[11px] font-mono font-semibold tabular-nums"
                  style={{ color }}
                >
                  {pct}
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* Canvas + interaction layer */}
      <div
        ref={containerRef}
        style={{ height, position: "relative", cursor: "crosshair" }}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        onTouchMove={handleTouchMove}
        onTouchEnd={handleMouseLeave}
      >
        <canvas ref={canvasRef} style={{ display: "block" }} />

        {/* Hover tooltip */}
        {hoverData && hoverData.length > 0 && (
          <div
            className="absolute pointer-events-none rounded-md px-2.5 py-2 text-xs font-mono tabular-nums z-10"
            style={{
              left: tooltipLeft,
              top: 4,
              background: isDark ? "rgba(15,15,20,0.92)" : "rgba(255,255,255,0.92)",
              border: `1px solid ${isDark ? "rgba(255,255,255,0.1)" : "rgba(0,0,0,0.1)"}`,
              boxShadow: "0 4px 12px rgba(0,0,0,0.3)",
              minWidth: 110,
            }}
          >
            {hoverTime && (
              <div
                className="mb-1 text-[10px]"
                style={{ color: isDark ? "rgba(255,255,255,0.4)" : "rgba(0,0,0,0.4)" }}
              >
                {formatTimeLabel(hoverTime, 0)}
              </div>
            )}
            {hoverData.map((d) => (
              <div key={d.label} className="flex items-center gap-1.5 leading-5">
                <span
                  style={{
                    width: 6,
                    height: 6,
                    borderRadius: "50%",
                    background: d.color,
                    display: "inline-block",
                    flexShrink: 0,
                  }}
                />
                <span
                  style={{
                    color: isDark ? "rgba(255,255,255,0.65)" : "rgba(0,0,0,0.65)",
                    maxWidth: 70,
                    overflow: "hidden",
                    textOverflow: "ellipsis",
                    whiteSpace: "nowrap",
                  }}
                >
                  {d.label}
                </span>
                <span
                  className="ml-auto font-semibold"
                  style={{ color: d.color }}
                >
                  {formatPercent(d.value)}
                </span>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

/**
 * @purrdict/hip4-ui — formatting utilities.
 *
 * Price/time/number formatters shared across components.
 */

/**
 * Format a mid price for display.
 *
 * For prediction markets (values 0–1), shows cents-style formatting:
 *   0.55 → "55¢" or "0.55" depending on style
 *
 * @param px    Price as a number or string
 * @param style "cents" | "decimal" | "percent" — default "decimal"
 */
export function formatMidPrice(
  px: number | string,
  style: "cents" | "decimal" | "percent" = "decimal",
): string {
  const p = typeof px === "string" ? parseFloat(px) : px;
  if (isNaN(p)) return "—";

  if (style === "cents") {
    return `${(p * 100).toFixed(0)}¢`;
  }
  if (style === "percent") {
    return `${(p * 100).toFixed(1)}%`;
  }
  // Decimal — strip trailing zeros after 4 decimal places.
  return p.toFixed(4).replace(/\.?0+$/, "");
}

/**
 * Format a USDH amount for display.
 *
 * @param amount  Amount as a number
 * @param compact Show compact form for large numbers (e.g. "$1.2K")
 */
export function formatUsdh(amount: number, compact = false): string {
  if (isNaN(amount)) return "$0";
  if (compact && amount >= 1_000) {
    if (amount >= 1_000_000) return `$${(amount / 1_000_000).toFixed(1)}M`;
    if (amount >= 1_000) return `$${(amount / 1_000).toFixed(1)}K`;
  }
  return `$${amount.toLocaleString("en-US", { minimumFractionDigits: 2, maximumFractionDigits: 2 })}`;
}

/**
 * Format a countdown from now to a future date.
 *
 * Returns:
 *   "2h 15m 30s" for > 2 hours
 *   "14m 30s"    for < 2 hours
 *   "45s"        for < 1 minute
 *   "Settled"    for past dates
 */
export function formatCountdown(expiry: Date): string {
  const msLeft = expiry.getTime() - Date.now();
  if (msLeft <= 0) return "Settled";

  const secs = Math.floor(msLeft / 1000);
  const mins = Math.floor(secs / 60);
  const hours = Math.floor(mins / 60);
  const days = Math.floor(hours / 24);

  if (days > 0) {
    const h = hours % 24;
    return `${days}d ${h}h`;
  }
  if (hours > 0) {
    const m = mins % 60;
    const s = secs % 60;
    return `${hours}h ${m}m ${s}s`;
  }
  if (mins > 0) {
    const s = secs % 60;
    return `${mins}m ${s}s`;
  }
  return `${secs}s`;
}

/**
 * Format a period string to human-readable label.
 *
 * "1m" → "1 Min"
 * "15m" → "15 Min"
 * "1h" → "1 Hour"
 * "1d" → "1 Day"
 */
export function formatPeriod(period: string): string {
  const match = period.match(/^(\d+)(m|h|d)$/);
  if (!match) return period;
  const n = parseInt(match[1]);
  const unit = match[2];
  const plural = n > 1;
  if (unit === "m") return `${n} Min`;
  if (unit === "h") return `${n} Hour${plural ? "s" : ""}`;
  if (unit === "d") return `${n} Day${plural ? "s" : ""}`;
  return period;
}

/**
 * Format a target price for display.
 *
 * 66200 → "66,200"
 * 66200.5 → "66,200.5"
 */
export function formatTargetPrice(price: number): string {
  return price.toLocaleString("en-US", {
    maximumFractionDigits: 2,
    minimumFractionDigits: 0,
  });
}

/**
 * Parse a mid price string to a number, returning 0 for invalid inputs.
 */
export function parseMid(s: string | undefined): number {
  if (!s) return 0;
  const n = parseFloat(s);
  return isNaN(n) ? 0 : n;
}

/**
 * Compute implied "No" price from a "Yes" price (since Yes + No = 1).
 */
export function noPrice(yesPx: number): number {
  return Math.max(0, Math.min(1, 1 - yesPx));
}
